PORTAL_PAGE_HTML = '\n<!doctype html>\n<html lang="zh-CN">\n<head>\n  <meta charset="utf-8">\n  <meta name="viewport" content="width=device-width, initial-scale=1">\n  <title>Tool Nexus Portal</title>\n  <style>\n    :root {\n      --navy: #001f3f;\n      --navy-2: #0b2f57;\n      --navy-3: #173f6b;\n      --bg: #f5f7fb;\n      --panel: #ffffff;\n      --soft: #f1f4f8;\n      --line: #e7ecf3;\n      --text: #0b223d;\n      --muted: #7a8797;\n      --green: #22c55e;\n      --blue: #3b82f6;\n      --amber: #f59e0b;\n      --red: #ef4444;\n      --shadow: 0 18px 50px rgba(0, 31, 63, .08);\n      --radius: 28px;\n    }\n    * { box-sizing: border-box; }\n    body { margin: 0; min-height: 100vh; color: var(--text); font-family: "Microsoft YaHei", "PingFang SC", "Noto Sans SC", "Segoe UI", sans-serif; background: var(--bg); }\n    button, input, select { font: inherit; }\n    a { color: inherit; text-decoration: none; }\n    .topbar { height: 72px; background: var(--navy); color: white; display: flex; align-items: center; justify-content: space-between; padding: 0 30px; box-shadow: 0 8px 24px rgba(0,31,63,.18); position: sticky; top: 0; z-index: 10; }\n    .brand { display: flex; align-items: center; gap: 12px; font-weight: 900; font-size: 20px; letter-spacing: .02em; }\n    .brand-icon { width: 34px; height: 34px; display: grid; place-items: center; border-radius: 12px; background: rgba(255,255,255,.12); }\n    .top-actions { display: flex; align-items: center; gap: 14px; }\n    .top-link { opacity: .88; font-weight: 700; padding: 10px 8px; border-bottom: 2px solid transparent; }\n    .top-link.active { opacity: 1; border-color: white; }\n    .user-chip { display: flex; align-items: center; gap: 12px; padding: 9px 14px; border-radius: 14px; background: rgba(255,255,255,.1); }\n    .avatar { width: 34px; height: 34px; border-radius: 999px; background: linear-gradient(135deg, #dbeafe, #93c5fd); color: var(--navy); display: grid; place-items: center; font-weight: 900; }\n    .page { display: grid; grid-template-columns: 320px 1fr; min-height: calc(100vh - 72px); }\n    .sidebar { background: #f0f2f6; border-right: 1px solid var(--line); padding: 30px 16px; display: flex; flex-direction: column; justify-content: space-between; }\n    .profile { display: flex; gap: 14px; align-items: center; padding: 8px 12px 26px; }\n    .profile .avatar { width: 58px; height: 58px; box-shadow: var(--shadow); }\n    .profile h3 { margin: 0 0 4px; font-size: 18px; }\n    .profile p { margin: 0; color: var(--muted); font-size: 13px; }\n    .menu { display: grid; gap: 10px; }\n    .menu-item { display: flex; align-items: center; gap: 12px; padding: 15px 18px; border-radius: 12px; color: #345066; font-weight: 800; }\n    .menu-item.active { background: var(--navy-2); color: white; box-shadow: 0 12px 28px rgba(0,31,63,.2); }\n    .hint-card { margin: 20px 10px 0; border: 1px solid #d6dde8; border-radius: 16px; padding: 16px; color: #516071; font-size: 13px; line-height: 1.65; background: #eef2f6; }\n    .content { padding: 44px min(56px, 4vw); overflow: hidden; }\n    .hero-row { display: flex; justify-content: space-between; gap: 24px; align-items: flex-start; margin-bottom: 30px; }\n    .eyebrow { display: flex; align-items: center; gap: 8px; color: #7d8ca0; font-weight: 900; letter-spacing: .18em; text-transform: uppercase; font-size: 12px; margin-bottom: 8px; }\n    h1 { margin: 0; color: var(--navy); font-size: clamp(34px, 4vw, 56px); line-height: 1; letter-spacing: -.05em; font-family: Georgia, "Microsoft YaHei", serif; }\n    .subtitle { margin: 12px 0 0; color: #516071; font-weight: 700; }\n    .stat-row { display: flex; gap: 16px; flex-wrap: wrap; }\n    .stat-card { min-width: 160px; padding: 18px 22px; border-radius: 26px; background: var(--panel); box-shadow: var(--shadow); display: flex; gap: 14px; align-items: center; }\n    .stat-icon { width: 52px; height: 52px; border-radius: 18px; background: var(--soft); display: grid; place-items: center; color: var(--navy); font-weight: 900; }\n    .stat-card small { color: #8a98aa; font-weight: 800; }\n    .stat-card strong { display: block; margin-top: 4px; font-size: 28px; color: var(--navy); }\n    .grid { display: grid; grid-template-columns: minmax(0, 1.18fr) minmax(420px, .82fr); gap: 24px; align-items: start; }\n    .panel { background: var(--panel); border: 1px solid var(--line); border-radius: var(--radius); box-shadow: var(--shadow); padding: 28px; }\n    .panel-head { display: flex; align-items: center; justify-content: space-between; gap: 16px; margin-bottom: 22px; }\n    .panel-title { display: flex; align-items: center; gap: 12px; }\n    .bar { width: 6px; height: 28px; border-radius: 999px; background: var(--navy); }\n    h2 { margin: 0; color: var(--navy); font-size: 24px; font-family: Georgia, "Microsoft YaHei", serif; }\n    .muted { color: var(--muted); font-size: 13px; line-height: 1.65; }\n    .btn { border: 0; border-radius: 14px; padding: 13px 18px; font-weight: 900; cursor: pointer; }\n    .btn-primary { background: var(--navy); color: white; box-shadow: 0 14px 24px rgba(0,31,63,.16); }\n    .btn-soft { background: var(--soft); color: var(--navy); }\n    .btn-danger { background: #fee2e2; color: #991b1b; }\n    .project-list { display: grid; gap: 14px; }\n    .project { display: grid; grid-template-columns: 1fr auto; gap: 18px; align-items: center; padding: 18px 20px; border: 1px solid var(--line); border-radius: 22px; background: #fff; box-shadow: 0 8px 22px rgba(0,31,63,.04); }\n    .project h3 { margin: 0 0 6px; font-size: 18px; color: var(--navy); }\n    .host { color: #8a98aa; font-size: 13px; }\n    .tags { display: flex; flex-wrap: wrap; gap: 8px; margin-top: 12px; }\n    .tag { border-radius: 999px; padding: 6px 10px; background: #eef2f6; color: #526172; font-size: 12px; font-weight: 900; }\n    .tag.green { background: #dcfce7; color: #166534; }\n    .tag.blue { background: #dbeafe; color: #1e40af; }\n    .tag.red { background: #fee2e2; color: #991b1b; }\n    form { display: grid; gap: 14px; }\n    label { display: grid; gap: 7px; color: #7b89a0; font-weight: 900; font-size: 12px; letter-spacing: .04em; }\n    input, select { width: 100%; border: 0; border-bottom: 2px solid #c8d1de; background: transparent; padding: 13px 4px; color: #172033; outline: none; }\n    input:focus, select:focus { border-color: var(--navy); }\n    .row { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }\n    .whitelist { border: 1px solid var(--line); background: #fbfcfe; border-radius: 18px; padding: 16px; }\n    .check-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); gap: 10px; margin-top: 12px; }\n    .check { display: flex; align-items: center; gap: 9px; background: white; border: 1px solid var(--line); border-radius: 12px; padding: 10px; color: #223955; font-weight: 800; }\n    .check input { width: auto; }\n    .notice { min-height: 20px; color: var(--muted); font-size: 13px; }\n    .notice.error { color: var(--red); }\n    .notice.success { color: #15803d; }\n    .config { background: var(--navy); color: #dbeafe; border-radius: 18px; padding: 16px; overflow: auto; font: 12px/1.65 Consolas, "Cascadia Mono", monospace; }\n    .user-list { display: grid; gap: 10px; margin-top: 16px; }\n    .user { display: flex; align-items: center; justify-content: space-between; padding: 12px 14px; border-radius: 14px; background: #f7f9fc; border: 1px solid var(--line); }\n    .empty { border: 1px dashed #c8d1de; border-radius: 20px; padding: 24px; color: var(--muted); background: #fbfcfe; }\n    .hidden { display: none !important; }\n    @media (max-width: 1120px) { .page { grid-template-columns: 1fr; } .sidebar { display: none; } .grid { grid-template-columns: 1fr; } .hero-row { flex-direction: column; } }\n    @media (max-width: 680px) { .topbar { padding: 0 16px; } .content { padding: 26px 16px; } .row { grid-template-columns: 1fr; } .project { grid-template-columns: 1fr; } }\n  </style>\n</head>\n<body>\n  <header class="topbar">\n    <div class="brand"><span class="brand-icon">?</span><span>Tool Nexus ??????</span></div>\n    <nav class="top-actions">\n      <a class="top-link active" href="/">??</a>\n      <button id="refreshButton" class="btn btn-soft">??</button>\n      <button id="logoutButton" class="btn btn-soft hidden">??</button>\n      <a id="loginLink" href="/login"><button class="btn btn-soft" type="button">??</button></a>\n      <div class="user-chip"><span class="avatar" id="avatarText">TN</span><span id="topUser">???</span></div>\n    </nav>\n  </header>\n\n  <div class="page">\n    <aside class="sidebar">\n      <div>\n        <div class="profile"><div class="avatar" id="sideAvatar">TN</div><div><h3 id="sideUser">???</h3><p>Tool Nexus ??</p></div></div>\n        <div class="menu">\n          <a class="menu-item active" href="#projects">? ????</a>\n          <a class="menu-item" href="#new-project">? ????</a>\n          <a class="menu-item" href="#users">? ????</a>\n          <a class="menu-item" href="#config">? ????</a>\n        </div>\n      </div>\n      <div class="hint-card"><strong>????</strong><br>???????????????????? frpc ?? frp.aim888888.xyz:7000?</div>\n    </aside>\n\n    <main class="content">\n      <section class="hero-row">\n        <div>\n          <div class="eyebrow">INTERNAL TOOL PORTAL</div>\n          <h1>?????????</h1>\n          <p class="subtitle">???????????????? FRP ?????</p>\n        </div>\n        <div class="stat-row">\n          <div class="stat-card"><div class="stat-icon">P</div><div><small>???</small><strong id="projectCount">0</strong></div></div>\n          <div class="stat-card"><div class="stat-icon">U</div><div><small>???</small><strong id="userCount">0</strong></div></div>\n        </div>\n      </section>\n\n      <section class="grid">\n        <div class="panel" id="projects">\n          <div class="panel-head"><div class="panel-title"><span class="bar"></span><div><h2>????</h2><p class="muted">????????????????????????</p></div></div></div>\n          <div id="projectList" class="project-list"></div>\n          <div id="projectEmpty" class="empty hidden">???????</div>\n        </div>\n\n        <div style="display:grid; gap:24px;">\n          <div class="panel" id="new-project">\n            <div class="panel-head"><div class="panel-title"><span class="bar"></span><div><h2>??????</h2><p class="muted">?????????????</p></div></div></div>\n            <form id="projectForm">\n              <label>????<input id="projectName" placeholder="?????????" required></label>\n              <div class="row">\n                <label>?????<input id="projectSubdomain" placeholder="???image-tool" required pattern="[a-z0-9-]+"></label>\n                <label>????<select id="projectVisibility"><option value="true">???owner + ???</option><option value="false">?????????</option></select></label>\n              </div>\n              <div id="whitelistBox" class="whitelist"><strong>?????</strong><p class="muted">owner ??????????????</p><div id="whitelistUsers" class="check-grid"></div></div>\n              <button class="btn btn-primary" type="submit">????</button>\n              <div id="formNotice" class="notice"></div>\n            </form>\n            <pre id="configPreview" class="config">customDomains will appear here after creating a project.</pre>\n          </div>\n\n          <div class="panel" id="users">\n            <div class="panel-head"><div class="panel-title"><span class="bar"></span><div><h2>????</h2><p class="muted">?????????????????</p></div></div></div>\n            <form id="userForm">\n              <div class="row"><label>???<input id="newUsername" placeholder="???lisi" required></label><label>????<input id="newPassword" type="password" minlength="6" required></label></div>\n              <button class="btn btn-soft" type="submit">????</button>\n              <div id="userNotice" class="notice"></div>\n            </form>\n            <div id="userList" class="user-list"></div>\n          </div>\n        </div>\n      </section>\n    </main>\n  </div>\n\n<script>\nconst state = { authenticated:false, user:null, projects:[], users:[] };\nconst $ = (id) => document.getElementById(id);\nfunction escapeHtml(v){return String(v).replace(/[&<>"]/g, c => ({\'&\':\'&amp;\',\'<\':\'&lt;\',\'>\':\'&gt;\',\'"\':\'&quot;\'}[c]));}\nfunction setNotice(el,msg,kind=\'\'){el.textContent=msg||\'\';el.className=\'notice\'+(kind?\' \'+kind:\'\');}\nasync function fetchJson(url,opt={}){const h=opt.body?{\'Content-Type\':\'application/json\',...(opt.headers||{})}:(opt.headers||{});const r=await fetch(url,{credentials:\'include\',...opt,headers:h});const t=await r.text();let p=null;try{p=t?JSON.parse(t):null}catch{p={message:t}}if(!r.ok)throw new Error(p?.detail||p?.message||\'Request failed\');return p;}\nfunction initials(name){return (name||\'TN\').slice(0,2).toUpperCase();}\nfunction renderSession(){const logged=state.authenticated&&state.user; $(\'loginLink\').classList.toggle(\'hidden\',logged); $(\'logoutButton\').classList.toggle(\'hidden\',!logged); const name=logged?state.user.username:\'???\'; $(\'topUser\').textContent=name; $(\'sideUser\').textContent=name; $(\'avatarText\').textContent=initials(name); $(\'sideAvatar\').textContent=initials(name);}\nfunction accessLabel(v){return v===\'owner\'?\'Owner\':v===\'shared\'?\'Whitelist\':v===\'public\'?\'Public\':v;}\nfunction renderProjects(){ $(\'projectCount\').textContent=state.projects.length; $(\'projectList\').innerHTML=\'\'; $(\'projectEmpty\').classList.toggle(\'hidden\',state.projects.length>0); for(const p of state.projects){const host=p.subdomain+\'.aim888888.xyz\'; const granted=(p.granted_users||[]).map(u=>escapeHtml(u.username)).join(\', \')||\'None\'; const card=document.createElement(\'article\'); card.className=\'project\'; card.innerHTML=`<div><h3>${escapeHtml(p.name)}</h3><div class="host">${host}</div><div class="tags"><span class="tag blue">${accessLabel(p.access_type)}</span><span class="tag ${p.is_private?\'red\':\'green\'}">${p.is_private?\'Private\':\'Public\'}</span><span class="tag">Owner: ${escapeHtml(p.owner_username)}</span><span class="tag">Whitelist: ${granted}</span></div></div><a class="btn btn-soft" href="https://${host}" target="_blank">??</a>`; $(\'projectList\').appendChild(card);}}\nfunction renderUsers(){ $(\'userCount\').textContent=state.users.length; $(\'userList\').innerHTML=\'\'; $(\'whitelistUsers\').innerHTML=\'\'; for(const u of state.users){const row=document.createElement(\'div\'); row.className=\'user\'; row.innerHTML=`<strong>${escapeHtml(u.username)}</strong><span class="muted">ID ${u.id}</span>`; $(\'userList\').appendChild(row); if(state.user&&u.id!==state.user.id){const lab=document.createElement(\'label\'); lab.className=\'check\'; lab.innerHTML=`<input type="checkbox" value="${u.id}"><span>${escapeHtml(u.username)}</span>`; $(\'whitelistUsers\').appendChild(lab);}} if(!$(\'whitelistUsers\').children.length){$(\'whitelistUsers\').innerHTML=\'<p class="muted">No other users yet.</p>\';}}\nfunction renderVisibility(){ $(\'whitelistBox\').classList.toggle(\'hidden\',$(\'projectVisibility\').value!==\'true\'); }\nasync function loadSession(){const s=await fetchJson(\'/api/me\');state.authenticated=s.authenticated;state.user=s.user;renderSession();}\nasync function loadUsers(){if(!state.authenticated)return;state.users=await fetchJson(\'/api/users\');renderUsers();}\nasync function loadProjects(){if(!state.authenticated)return;state.projects=await fetchJson(\'/api/my-projects\');renderProjects();}\nasync function reloadAll(){await loadSession(); if(state.authenticated){await loadUsers(); await loadProjects();}}\n$(\'refreshButton\').onclick=()=>reloadAll().catch(e=>setNotice($(\'formNotice\'),e.message,\'error\'));\n$(\'logoutButton\').onclick=async()=>{await fetchJson(\'/api/logout\',{method:\'POST\'});location.href=\'/login\';};\n$(\'projectVisibility\').onchange=renderVisibility;\n$(\'projectForm\').onsubmit=async(e)=>{e.preventDefault(); const sub=$(\'projectSubdomain\').value.trim().toLowerCase(); const isPrivate=$(\'projectVisibility\').value===\'true\'; const ids=isPrivate?[...$(\'whitelistUsers\').querySelectorAll(\'input:checked\')].map(i=>Number(i.value)):[]; try{await fetchJson(\'/api/projects\',{method:\'POST\',body:JSON.stringify({name:$(\'projectName\').value.trim(),subdomain:sub,is_private:isPrivate,whitelist_user_ids:ids})}); setNotice($(\'formNotice\'),\'Project created.\',\'success\'); $(\'configPreview\').textContent=`serverAddr = "frp.aim888888.xyz"\\nserverPort = 7000\\nauth.token = "YOUR_TOKEN"\\ntransport.tls.enable = true\\n\\n[[proxies]]\\nname = "${sub}"\\ntype = "http"\\nlocalIP = "127.0.0.1"\\nlocalPort = 3000\\ncustomDomains = ["${sub}.aim888888.xyz"]`; e.target.reset(); renderVisibility(); await loadProjects();}catch(err){setNotice($(\'formNotice\'),err.message,\'error\');}};\n$(\'userForm\').onsubmit=async(e)=>{e.preventDefault(); try{await fetchJson(\'/api/users\',{method:\'POST\',body:JSON.stringify({username:$(\'newUsername\').value.trim(),password:$(\'newPassword\').value})}); setNotice($(\'userNotice\'),\'User created.\',\'success\'); e.target.reset(); await loadUsers();}catch(err){setNotice($(\'userNotice\'),err.message,\'error\');}};\nrenderVisibility(); reloadAll().catch(e=>setNotice($(\'formNotice\'),e.message,\'error\'));\n</script>\n</body>\n</html>\n'

